SELECT informationId,title,infImgUrl,publishTime
FROM information

  
    AND infType = #{infType}
  
  AND infType IS NOT NULL

ORDER BY createdDate

  limit #{offset}, #{limit}

SELECT count(*) FROM information
AND infType = #{infType}
AND infType IS NOT NULL

